<a href="/portal/work-order-templates" class="small text-decoration-none">&larr; Work Order Templates</a><h1 class="h3 mt-2"><?=e($template['name'])?></h1><p class="text-muted"><?=e($template['service_summary']??'')?> · <?=e($template['service_name']??'Any service')?></p><div class="row g-4"><div class="col-lg-4"><div class="card shadow-sm"><div class="card-body"><h2 class="h5">Add Task</h2><form method="post" action="/portal/work-order-templates/<?=$template['id']?>/tasks" class="row g-3"><?=csrf_field()?><div class="col-12"><label class="form-label">Task</label><input name="task_label" class="form-control" required></div><div class="col-6"><input type="number" name="sort_order" value="100" class="form-control"></div><div class="col-6 form-check mt-2"><input type="checkbox" name="required" checked class="form-check-input" id="wor"><label for="wor" class="form-check-label">Required</label></div><div class="col-12"><button class="btn btn-primary w-100">Add Task</button></div></form></div></div></div><div class="col-lg-8"><div class="card shadow-sm"><div class="card-body"><h2 class="h5">Instructions</h2><p style="white-space:pre-wrap"><?=e($template['instructions']??'')?></p></div><div class="table-responsive"><table class="table mb-0"><thead><tr><th>Task</th><th>Required</th><th></th></tr></thead><tbody><?php foreach($tasks as $task):?><tr><td><?=e($task['task_label'])?></td><td><?=$task['required']?'Yes':'No'?></td><td><form method="post" action="/portal/work-order-template-tasks/<?=$task['id']?>/delete"><?=csrf_field()?><button class="btn btn-sm btn-outline-danger">Delete</button></form></td></tr><?php endforeach?></tbody></table></div></div></div></div>
